insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('bf3e4583-6104-532f-901b-97e7a85e82d4', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 72, 'Dr. Mason has personally run the Bellaire practice since 1993 (~33 yrs) and is a second-generation owner (father founded it 1957); license-tenure proxy puts her ~58-62, within the natural-exit window. Confidence is medium — age is a tenure proxy, not OV65/DOB.', 80, 'Long-established (since 1957, hers since 1993), needs-based recurring-revenue general/cosmetic practice in affluent Bellaire 77401, ~6 staff, 293+ aggregated positive reviews, clean license. Solo GP caps it slightly vs a multi-provider group; plausible SBA 7(a) size.', 68, 'Coasting tells stack: Mon-Thu-only schedule (Fri-Sun closed), single listed provider with no associate, longstanding practice with no visible recent expansion or hiring, and a second-generation owner near a natural exit. Healthy P&L, disengaged operating posture — not distress.', 86, 'Houston is one of the most active DSO/PE dental roll-up markets in the country; Bellaire/West-U is a premium ZIP that draws strong acquirer demand, and solo GP acquisitions there are routinely SBA-financed. ETA/independent-sponsor appetite is high.', 75, 'B_forward', 'Dr. Lora M. Mason, ~60 (license_tenure_proxy), runs Lora M. Mason, D.D.S., P.A. in Bellaire, Harris County. Dr. Mason has personally run the Bellaire practice since 1993 (~33 yrs) and is a second-generation owner (father founded it 1957); license-tenure proxy puts her ~58-62, within the natural-exit window. Confidence is medium — age is a tenure proxy, not OV65/DOB. Coasting tells stack: Mon-Thu-only schedule (Fri-Sun closed), single listed provider with no associate, longstanding practice with no visible recent expansion or hiring, and a second-generation owner near a natural exit. Healthy P&L, disengaged operating posture — not distress. Houston is one of the most active DSO/PE dental roll-up markets in the country; Bellaire/West-U is a premium ZIP that draws strong acquirer demand, and solo GP acquisitions there are routinely SBA-financed. ETA/independent-sponsor appetite is high. Composite 75/100. Tier B — hand to the buyer / searcher community.', 'AI front-desk + automated recall to reactivate the lapsed-hygiene base, online scheduling, modern PMS migration, and automated review generation — a plausible 1.5-2x EBITDA path over 18-24 months in a premium catchment.', 'medium', 0.6),
('28886eca-83f3-5389-b4a9-03648d1ae103', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 72, 'Solo private practice in Houston for 30+ years (University of Maryland Dental School grad); license-tenure proxy ~58-62. Settled, established, near a natural-exit window. Medium confidence — proxy age only, no OV65/DOB.', 76, 'Clean 30+ year aesthetic/restorative/implant practice in the affluent Upper Kirby/Greenway 77098 corridor; recurring hygiene-recall base; solo GP-cosmetic with systems in place; SBA-financeable. Solo + smaller review footprint caps it modestly.', 70, 'Strong coasting profile: solo provider with no associate, Mon-Thu schedule (Fri-Sun closed), no visible recent expansion/hiring, longstanding single location. Healthy practice, owner has stopped pushing growth.', 85, 'Inner-loop Houston (Upper Kirby/Greenway) is a hot DSO/PE catchment; restorative-heavy solo practices in this ZIP are highly bankable and command active buy-side interest.', 74, 'B_forward', 'Dr. Mary F. Riley, ~60 (license_tenure_proxy), runs Mary F. Riley, D.D.S., P.C. in Houston, Harris County. Solo private practice in Houston for 30+ years (University of Maryland Dental School grad); license-tenure proxy ~58-62. Settled, established, near a natural-exit window. Medium confidence — proxy age only, no OV65/DOB. Strong coasting profile: solo provider with no associate, Mon-Thu schedule (Fri-Sun closed), no visible recent expansion/hiring, longstanding single location. Healthy practice, owner has stopped pushing growth. Inner-loop Houston (Upper Kirby/Greenway) is a hot DSO/PE catchment; restorative-heavy solo practices in this ZIP are highly bankable and command active buy-side interest. Composite 74/100. Tier B — hand to the buyer / searcher community.', 'Online booking + AI front desk + recall automation to recapture the dormant hygiene base; modern PMS and automated reviews; reposition the cosmetic line for higher-value cases — credible EBITDA uplift over 18-24 months.', 'medium', 0.55),
('70222cd8-3fa5-569a-bf76-6a8e5988ddd8', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 75, 'Dr. Frazar (UT Dental Branch Houston) has practiced in Bellaire/West-U since 1989 (~37 yrs); license-tenure proxy ~62-65 — squarely in the natural-exit window. Medium confidence (proxy only).', 85, 'High-end cosmetic/restorative practice (6,000+ smiles transformed), 2 providers (Dr. Frazar + Dr. Tom Hedge), ~10 staff, premium Bellaire ZIP, repeatedly in Texas Monthly ''Top Dentists'', clean record — a genuinely sellable, financeable asset.', 62, 'Some coasting tells: Mon-Thu plus a short Fri (8-4), founder near natural exit, no new associate beyond the long-standing second dentist. But a cosmetic-driven practice that''s still marketing actively and media-visible is less obviously ''disengaged'' — moderate L3.', 88, 'Premium cosmetic dental practices in inner-loop Houston are top of the buy-side wish list for DSOs and high-net-worth dentist-buyers; Bellaire commands a strong multiple and easy SBA financing.', 76, 'B_forward', 'Dr. Kathy Frazar, ~62 (license_tenure_proxy), runs The Houston Dentists (Kathy Frazar, DDS) in Bellaire, Harris County. Dr. Frazar (UT Dental Branch Houston) has practiced in Bellaire/West-U since 1989 (~37 yrs); license-tenure proxy ~62-65 — squarely in the natural-exit window. Medium confidence (proxy only). Some coasting tells: Mon-Thu plus a short Fri (8-4), founder near natural exit, no new associate beyond the long-standing second dentist. But a cosmetic-driven practice that''s still marketing actively and media-visible is less obviously ''disengaged'' — moderate L3. Premium cosmetic dental practices in inner-loop Houston are top of the buy-side wish list for DSOs and high-net-worth dentist-buyers; Bellaire commands a strong multiple and easy SBA financing. Composite 76/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + concierge recall, online scheduling, structured cosmetic-case marketing, and a modern PMS — plus an associate-to-equity glide path; the brand equity already supports premium pricing, so the lever is throughput and case acceptance.', 'medium', 0.6),
('e05f274d-ee31-543b-b6d1-2ef9c11adb51', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 80, 'Dr. Le has been practicing dentistry since 1987 (~39 yrs; UT Health San Antonio); license-tenure proxy ~62-67 — strong natural-exit signal. Wife Ann manages the office, so it''s a husband-and-wife operation with no obvious junior succession. Medium confidence (proxy age).', 72, 'Clean, modern Memorial/Spring-Branch practice with general + cosmetic + ortho and a 2nd dentist; recurring hygiene base; affluent 77024 ZIP. Caveat: the current practice was founded 2015 (the prior practice was sold), so ''years in business'' for the entity is ~11, which trims sellability slightly though not below the 5-yr gate.', 55, 'Mixed signals: long-tenured owner near exit and a small two-person operation argue for coasting, but the 2015 buildout / modern facility / active marketing argue against ''digital decay''. Net moderate — the trigger here is owner age more than visible disengagement.', 85, 'Memorial/Bunker Hill (77024) is one of Houston''s wealthiest catchments and a prime DSO/PE target; modern facility + long-tenured owner is an attractive bolt-on; SBA-financeable.', 71, 'B_forward', 'Dr. Tri M. Le, ~63 (license_tenure_proxy), runs Bunker Hill Dentistry (Tri M. Le, DDS) in Houston, Harris County. Dr. Le has been practicing dentistry since 1987 (~39 yrs; UT Health San Antonio); license-tenure proxy ~62-67 — strong natural-exit signal. Wife Ann manages the office, so it''s a husband-and-wife operation with no obvious junior succession. Medium confidence (proxy age). Mixed signals: long-tenured owner near exit and a small two-person operation argue for coasting, but the 2015 buildout / modern facility / active marketing argue against ''digital decay''. Net moderate — the trigger here is owner age more than visible disengagement. Memorial/Bunker Hill (77024) is one of Houston''s wealthiest catchments and a prime DSO/PE target; modern facility + long-tenured owner is an attractive bolt-on; SBA-financeable. Composite 71/100. Tier B — hand to the buyer / searcher community.', 'Recall automation + AI front desk to drive hygiene reactivation and case acceptance; associate-to-owner transition plan; the physical plant is already modern, so the lever is volume and digital workflows.', 'medium', 0.55),
('fab58cf9-4900-578b-948a-036dc6c7c432', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 68, 'Dr. Moore has practiced 30+ years; comes from a multi-generation dentist family (grandfather + father). License-tenure proxy ~58-62. Nuance: his son Dr. Andrew Moore now practices ~3 days/week — a possible in-family succession path, which can either keep him from selling or set up a structured exit. Medium-low confidence.', 78, 'Clean, well-reviewed Clear Lake/Webster general+cosmetic practice, 30+ yrs, two providers (father + son), recurring hygiene base, plausible SBA size in a stable bayside catchment.', 52, 'The aging owner is the trigger, but bringing his son into the practice ~3 days/week is the opposite of ''no succession'' and suggests he hasn''t disengaged or decided to sell to an outsider. Limited other coasting tells visible. Moderate-low L3.', 82, 'Clear Lake/NASA-area Houston is a solid DSO/PE catchment; family-succession dynamics can complicate an outright sale, which trims the ''how hot for an outside buyer'' read slightly.', 68, 'B_forward', 'Dr. Michael G. Moore, ~60 (license_tenure_proxy), runs Aesthetic & Comprehensive Dentistry of Clear Lake (Michael G. Moore, DDS) in Webster, Harris County. Dr. Moore has practiced 30+ years; comes from a multi-generation dentist family (grandfather + father). License-tenure proxy ~58-62. Nuance: his son Dr. Andrew Moore now practices ~3 days/week — a possible in-family succession path, which can either keep him from selling or set up a structured exit. Medium-low confidence. The aging owner is the trigger, but bringing his son into the practice ~3 days/week is the opposite of ''no succession'' and suggests he hasn''t disengaged or decided to sell to an outsider. Limited other coasting tells visible. Moderate-low L3. Clear Lake/NASA-area Houston is a solid DSO/PE catchment; family-succession dynamics can complicate an outright sale, which trims the ''how hot for an outside buyer'' read slightly. Composite 68/100. Tier B — hand to the buyer / searcher community.', 'If the family route doesn''t materialize: recall automation + AI front desk + online scheduling + modern PMS; otherwise this is more a ''watch / forward to a DSO that does partnership-buyouts'' play than a Gideon-buys-it-himself one.', 'low', 0.5),
('8e28dcc8-4e18-593b-bfab-f9a21fe17de0', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 74, 'Dr. Hall graduated UT Dental School Houston in 1990 (~36 yrs licensed), practiced 10 yrs with his father, full-time in Katy since 2000; license-tenure proxy ~58-62. Solid natural-exit profile; no junior partner mentioned. Medium confidence.', 76, 'Established Katy general/family practice (Katy office since 1997, full-time since 2000), AGD Fellow owner, recurring hygiene base, ~6 staff, strong reviews (5.0 avg) in a growth suburb. Solo GP — caps slightly; SBA-financeable.', 66, 'Coasting tells: Mon-Thu 8-5 plus a short Fri (8-1), single listed provider with no associate, mature single location with no visible recent expansion. Healthy, well-reviewed — disengaged-operator profile, not distress.', 84, 'West Houston / Katy is a high-growth, high-demand DSO and independent-buyer market; a clean solo GP with a loyal base in 77450 is very bankable.', 74, 'B_forward', 'Dr. Byron ''Joey'' Hall, ~60 (license_tenure_proxy), runs Katy Family Dentists (Byron J. Hall, DDS) in Katy, Harris County. Dr. Hall graduated UT Dental School Houston in 1990 (~36 yrs licensed), practiced 10 yrs with his father, full-time in Katy since 2000; license-tenure proxy ~58-62. Solid natural-exit profile; no junior partner mentioned. Medium confidence. Coasting tells: Mon-Thu 8-5 plus a short Fri (8-1), single listed provider with no associate, mature single location with no visible recent expansion. Healthy, well-reviewed — disengaged-operator profile, not distress. West Houston / Katy is a high-growth, high-demand DSO and independent-buyer market; a clean solo GP with a loyal base in 77450 is very bankable. Composite 74/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation to capture the suburb''s population growth, online scheduling, modern PMS, automated reviews — plus an associate-to-equity path; clear EBITDA upside over 18-24 months.', 'medium', 0.6),
('e1ecfc6a-6b55-56ba-b183-fba8d865f343', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 42, 'Practice itself dates to 1950, but Dr. Nugent only acquired it in 2008 (~18 yrs as owner) — license-tenure proxy puts him ~45-52, well shy of a natural-exit window. He''s the wrong end of the age curve for this thesis; L1 is low.', 80, 'Genuinely strong asset: a 1950-founded independent (non-corporate) general/cosmetic/implant/sedation practice in Pasadena, multiple ''Best Dentist'' awards, recurring hygiene base, ~6 staff, clean record — very sellable, very financeable. The constraint is the owner isn''t a seller.', 28, 'Few coasting tells — Dr. Nugent actively markets (multiple Best-Dentist wins, fresh web presence) and is mid-career. Not disengaged; not winding down. Low L3.', 82, 'Pasadena/Southeast Houston has steady DSO interest and the practice''s brand and longevity make it attractive — but with a non-selling owner this is a ''watch'' rather than an actionable target.', 53, 'C_watch', 'Dr. Michael Nugent, ~50 (license_tenure_proxy), runs Michael Nugent, DDS in Pasadena, Harris County. Practice itself dates to 1950, but Dr. Nugent only acquired it in 2008 (~18 yrs as owner) — license-tenure proxy puts him ~45-52, well shy of a natural-exit window. He''s the wrong end of the age curve for this thesis; L1 is low. Few coasting tells — Dr. Nugent actively markets (multiple Best-Dentist wins, fresh web presence) and is mid-career. Not disengaged; not winding down. Low L3. Pasadena/Southeast Houston has steady DSO interest and the practice''s brand and longevity make it attractive — but with a non-selling owner this is a ''watch'' rather than an actionable target. Composite 53/100. Tier C — re-score in ~90 days.', 'Mostly N/A near-term — owner isn''t winding down. If circumstances change, the levers would be recall automation and online scheduling, but this stays on the watch list for now.', 'medium', 0.55),
('877c8e07-7aca-556d-8f7c-640d6a12ff33', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 60, 'Two-partner practice with 50+ years combined experience and a ~40-year practice history; tenure proxy puts the principals ~55-60. Two owners means a transition is plausible but not imminent, and there''s no clear single-owner exit clock. Low-medium confidence.', 82, 'High-performing NW Houston general/family/ortho/restorative practice with 1,000+ five-star reviews (4.9 Google), 2 dentists + ~10 staff, recurring hygiene base, clean record — very sellable and bankable.', 40, 'Few coasting tells: heavy active marketing, huge fresh review velocity, multi-service expansion (ortho added). This is a humming, growing practice — the trigger isn''t disengagement; at most it''s the partners'' ages. Low L3.', 84, 'NW Houston is a strong DSO/PE catchment and a 4.9-star 1,000+-review group is a prized bolt-on; easily SBA-financeable.', 63, 'B_forward', 'Dr. Eric Perkins (with Dr. Scott Driver), ~58 (license_tenure_proxy), runs Acadian Family Dental (Eric Perkins, DDS & Scott Driver, DDS) in Houston, Harris County. Two-partner practice with 50+ years combined experience and a ~40-year practice history; tenure proxy puts the principals ~55-60. Two owners means a transition is plausible but not imminent, and there''s no clear single-owner exit clock. Low-medium confidence. Few coasting tells: heavy active marketing, huge fresh review velocity, multi-service expansion (ortho added). This is a humming, growing practice — the trigger isn''t disengagement; at most it''s the partners'' ages. Low L3. NW Houston is a strong DSO/PE catchment and a 4.9-star 1,000+-review group is a prized bolt-on; easily SBA-financeable. Composite 63/100. Tier B — hand to the buyer / searcher community.', 'Limited near-term — already running modern marketing. If a partner exits, the play is a partnership buy-in / DSO partnership rather than a distressed turnaround.', 'low', 0.45)
